var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"으아… 빈틈이 없어. 별로 상대는 지친 것 같지도 않아.","JPN":"うう…隙がない。会長は全然疲れていないし。","ENG":"Ugh, I can't find an opening. She doesn't look exhausted, either.","TWN":"可惡…沒有破綻！她好像都不會累？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REBBIT_SUMMON_NULL_NULL","text":{"KOREA":"픽… 픽…","JPN":"ピィ……ピィ……","ENG":"Piiik... Piiik...","TWN":"嗶…嗶…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"기량은 훌륭하지만, 동작이 너무 크군요.","JPN":"技量はお見事ですが、動作が大袈裟すぎますね。","ENG":"You're good, but your moves are unnecessarily big.","TWN":"技巧不錯，可惜動作太大。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"공격 또한 너무 단조로워서 검을 한 번 맞대는 것만으로 흐름을 알 수 있어요.","JPN":"攻撃も単調すぎて、剣を交わすだけで動きの流れが読み取れます。","ENG":"Too predictable, too. I've figured out your style after our first clash of swords.","TWN":"攻擊的方式也太呆板，一下就可以摸清你的套路。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REBBIT_SUMMON_NULL_NULL","text":{"KOREA":"피이……","JPN":"ピィ……","ENG":"Piii...","TWN":"嗶……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REBBIT_SUMMON_NULL_NULL","text":{"KOREA":"피픽? 픽! 픽!","JPN":"ピィ？　ピー！　ピー！","ENG":"Piiipik? Piik! Piik!","TWN":"嗶嗶？嗶！嗶！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"음? 하늘에 UFO가 있다고요?","JPN":"え？　空にUFOがいるですって？","ENG":"Huh? There's a UFO in the sky?","TWN":"什麼？天上有UFO？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REBBIT_SUMMON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"REBBIT_SUMMON_NULL_NULL","text":{"KOREA":"피이익…","JPN":"ピィ……！","ENG":"Piiiik...","TWN":"嗶嗶…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"조금 당혹스럽군요.","JPN":"これは少々参りましたね。","ENG":"I'm a bit disconcerted.","TWN":"我應該沒眼花吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"실전에서 정말로 이런 속임수를 쓰는 경우를 보게 될 줄은 몰랐는데 말이죠.","JPN":"実戦でこんなトリックを使うケースを目にするとは思っていませんでした。","ENG":"I've never met anyone else using such a trick in a real fight.","TWN":"沒想到會在實戰中見識到這種小孩子的把戲。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"헥 헥… 더는 못 휘두르겠어.","JPN":"はぁはぁ……もう無理だよ。","ENG":"Huff, huff... I can't swing my gun anymore.","TWN":"呼呼…我沒力氣了啦！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"음…… 약점을 파악 당한 본관의 완벽한 패배로군.","JPN":"むむ……弱点を突かれた本官の完全な敗北だな。","ENG":"Mm... This is my complete defeat. She's seen through my weakness.","TWN":"嗯…本官的弱點完全被對方看穿，本官承認戰敗！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"갑작스럽게 과자 공세를 펼칠 줄은 예상하지 못 했다.","JPN":"急にお菓子攻撃をされるとは予想もできなかった。","ENG":"I can't believe she used cookies to distract me so all of a sudden.","TWN":"沒想到竟然會突然使出餅乾攻勢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"……냠-","JPN":"……(もぐもぐ)。","ENG":"*Yum*","TWN":"阿姆阿姆…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"역시…… 우리가 힘을 합쳐도 학생회장님에겐 안되는 건가.","JPN":"やっぱり……私たちが力を合わせても生徒会長には勝てないね。","ENG":"I knew it. Even among the three of us, we're no match for the Student President.","TWN":"果然……三個臭皮匠加起來，還是無法勝過一個學生會長嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아쉽지만, 패배를 인정할게요.","JPN":"残念ですが、私たちの敗北を認めます。","ENG":"This is disappointing, but we accept our defeat.","TWN":"雖然很遺憾，我承認是我們輸了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"좋은 승부였습니다.","JPN":"いい勝負でしたね。","ENG":"That was a good match.","TWN":"是場精彩的對決。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그럼 란체스터 2세는 제가 데려가도록 하죠.","JPN":"では、ランチェスター2世は私が預かりましょう。","ENG":"Now, I'll take Lanchester II with me.","TWN":"那蘭賈斯特二世我就打包帶走囉！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE_2"},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"무슨 일이죠?","JPN":"もしもし、いかがなさいましたか？","ENG":"What is it?","TWN":"什麼事？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아뇨, 후배들과 시간을 보내고 있던 참입니다만.","JPN":"いいえ、後輩たちと有意義な交流の時間を過ごしていたところですが。","ENG":"No. I've been spending time with the juniors.","TWN":"不，我和學妹們在一起。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그… 고양이의 소유권에 대한 논쟁을 조금……","JPN":"あの……猫の所有権についての論争を少し……","ENG":"In regard to, erm... the ownership of a, err... cat...","TWN":"那個…在爭貓咪扶養權……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"어쩔 수 없군요.","JPN":"仕方ありませんね。","ENG":"Understood.","TWN":"也只能這樣。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"알겠어요. 당장 돌아가도록 하죠.","JPN":"了解しました。今すぐ戻ります。","ENG":"Okay, I'll be right back.","TWN":"好的，我馬上回去。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어라? 어디 가세요, 사부?","JPN":"あれ？　どこに行くんですか、師匠？","ENG":"Err? Where are you going, Master?","TWN":"會長，你要去哪？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회에서 연락이 왔습니다.","JPN":"生徒会から連絡がありました。","ENG":"That call was from the Student Council.","TWN":"學生會打來找我。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양이 당장 돌아와서 오늘 일정을 돕지 않으면 임원 일을 관두겠다고 하는군요.","JPN":"シエル君に今すぐ戻って本日の生徒会の仕事を済ませないと、\\n役員の仕事を辞めると言われました。","ENG":"Ciel wants me to come back immediately and help her with today's schedule, or she'll leave the Council.","TWN":"西艾爾要我立刻回去協助處理今天的行程，否則他就辭職不幹！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"괘, 괜찮은 거에요, 그거?","JPN":"そ、それってまずいことですよね？","ENG":"Th-that doesn't sound good.","TWN":"這…這樣沒關係嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미안하게 됐어요.","JPN":"ごめんなさい。","ENG":"I'm sorry.","TWN":"對你們很抱歉！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"대련으로 머리를 좀 식히고 생각해보니, 고양이를 키우겠다는 제 판단이 경솔했다는 걸 알겠네요.","JPN":"頭を冷やしてよく考えてみたら、猫を飼うという私の判断が軽率だったことに気付きました。","ENG":"Now that my head is cleared through the duel, I know I was being irrational, wanting to raise the cat.","TWN":"打完後我腦袋有冷靜一點，說要養貓這個決定果然還是太過草率。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네? 그렇다는 건…?","JPN":"え？　それはつまり……？","ENG":"Sorry? You mean...","TWN":"什麼？那你的意思是…？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"어떻게든 시간을 만들어서 고양이를 책임질 수도 있겠지만……","JPN":"何とか時間を作って面倒をみることもできますが……","ENG":"I still could make time to take care of the cat...","TWN":"我是可以擠出時間來養牠……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그건 고양이를 키우고 싶은 저에게 있어 최선의 선택일 뿐. 란체스터 2세의 행복을 위한 최선이라곤 할 수 없겠죠.","JPN":"それは猫を飼いたい私にとって最善の選択というだけで、\\nランチェスター2世にとっての最善とは言えないでしょう。","ENG":"But if I did, that would only satisfy my desire for having a cat; it wouldn't make Lanchester II truly happy.","TWN":"但那只是站在我的立場去想而已，並不是以蘭賈斯特二世的幸福為優先考量！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"고양이의 처우는 여러분에게 맡기겠습니다. 양육에 필요한 지원도 학생회장의 이름을 걸고 약속하겠어요.","JPN":"ランチェスター2世の行き先は皆さんにお任せします。\\nお世話に必要な物資も生徒会長の名をかけて保証します。","ENG":"I'll trust you with the cat. I swear on my Student President title that I'll spare no effort to support you with his care.","TWN":"我決定交貓交給你們！如果需要任何幫助，我以學生會長的名義保證一定會提供協助！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"오오…!","JPN":"おお……！","ENG":"Ooo!","TWN":"喔喔…！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"와! 정말요?","JPN":"わぁ～！　本当ですか？","ENG":"Whoa! Really?","TWN":"哇！真的嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"…응? 하늘에서 의자가 내려오는데?","JPN":"…あれ？　空から椅子が下りてくる…？","ENG":"Mm? A chair is coming down from the sky.","TWN":"…嗯？有一張椅子從天而降？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐아암-","JPN":"ふぁあ～。","ENG":"*Yawn*","TWN":"哈啊啊～"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"안녕, 여러분-","JPN":"皆さん、おはよう。","ENG":"Hello, guys.","TWN":"大家哈囉～"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"오오, 이디스 동지! 오랜만이다!","JPN":"おお、イーディスではないか！　久しぶりだな！","ENG":"Ooo, Comrade Edith! Long time, no see!","TWN":"喔！是伊蒂絲同學，好久不見！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스? 혹시 학생회 업무 때문에 절 데리러 온 건가요?","JPN":"イーディス？　もしかして生徒会の業務でお迎えに来てくれたのですか？","ENG":"Edith? Did you come to pick me up for the Council schedule?","TWN":"伊蒂絲？是學生會派你來接我的嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"뭐 그런 것도 있지만-","JPN":"まあ、それもあるけどねぇ。","ENG":"Well, that, and...","TWN":"這算是理由之一啦～"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"루비야! 여기 있었구나!","JPN":"ルビー！　ここにいたんだね！","ENG":"Ruby! There you are!","TWN":"露比，原來你在這裡！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"루비?","JPN":"ルビー？","ENG":"Ruby?","TWN":"露比？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"저기, 이 분은 누구세요?","JPN":"あの、この方はどなたですか？","ENG":"I'm sorry, but who is she?","TWN":"請問，這位是？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"오는 길에 만났어. 회장이 묘사하던 그 고양이랑 똑같이 생긴 실종 전단지를 돌리고 있더라고.","JPN":"途中でたまたま会ったんだ。\\n会長が言っていたあの猫とソックリな迷子猫のチラシを配っていてねぇ。","ENG":"I met her on my way here. The missing cat printed on her handouts matched your description, President.","TWN":"我來的路上看到她在發協尋走失貓的傳單，結果發現她的貓長得跟會長描述得一模一樣。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그렇다는 건… 그 소녀가 막시무스의 원래 주인이라는 건가?","JPN":"つまり……この少女がマクシムスの元の飼い主ということか？","ENG":"This means... that girl is Maximus's owner.","TWN":"你的意思是…她是咖啡貓原本的主人？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"응- 며칠동안 애타게 찾았다는 모양이야. 하암-","JPN":"そうだねぇ。何日もずっと探していたらしいよ。ふぁ～あ。","ENG":"Yes, she's been looking for her for days. *Yawn*","TWN":"對，她好像已經找了好幾天了，哈啊～"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"갑자기 집을 나가서 걱정하고 찾아다녔는데, 여러분이 잘 보호해주셔서 정말 감사해요.","JPN":"急に家から飛び出して……ずっと心配してたんです。\\n皆さんが保護してくださったみたいで、本当に感謝しています。","ENG":"I was so worried because she left home all of a sudden. Thank you for taking good care of her.","TWN":"牠突然從家裡跑出去，我怕牠出事，就到處去找牠。謝謝你們把牠照顧得這麼好！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CAT_EXTRA_NULL_NULL","text":{"KOREA":"냥-","JPN":"ニャー。","ENG":"Meow.","TWN":"喵～"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_CAT_START"},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아뇨, 무사히 주인을 찾아서 다행입니다. 분명 이 아이도 사랑하는 주인을 다시 만나서 기쁘겠군요.","JPN":"いえ、飼い主さんが見つかってよかったです。\\nきっとこの子も家族と再会できて喜んでいるでしょう。","ENG":"No. I'm glad she's found her owner. I'm sure she's happy to see you again, too.","TWN":"別這麼說，幸好牠平安回到愛牠的主人身邊，相信牠一定也很開心。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"앞으로는 헤어지지 않도록 조심하세요.","JPN":"これからは家出しないように気をつけてくださいね。","ENG":"You should be careful not to lose her again.","TWN":"以後要小心，不要再走散囉！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"위험한 장소를 혼자 돌아다니다가, 저희 아카데미 학생들에게 구조되었으니까요.","JPN":"危険な場所で迷子になっていて、うちのアカデミー生徒に救助されたわけですから。","ENG":"She was found in a dangerous place by these students of the Academy.","TWN":"牠自己跑到危險的地方去，我們學院的學生看到就把牠救援出來。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"죄송해요!","JPN":"ごめんなさい！","ENG":"I'm sorry.","TWN":"真的很抱歉！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"그리고 정말 감사합니다!","JPN":"そして、本当にありがとうございます！","ENG":"And thank you so much.","TWN":"也謝謝你們！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"루비를 찾아주신 여러분! 정말 감사해요!","JPN":"ルビーを見つけてくれた皆さん！　本当にありがとうございました！","ENG":"Everyone, thank you for finding Ruby.","TWN":"謝謝你們幫我找回露比！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"괜찮아요! 그게 저희 동아리가 하는 일인 걸요.","JPN":"いえいえ！　それがこのサークルの仕事ですから。","ENG":"You're welcome. It's what we do as a club.","TWN":"小事情啦～這是我們社團該做的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"……","TWN":"……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"여러분은 고양이와 헤어지게 돼서 아쉽진 않나요?","JPN":"皆さんは猫とお別れすることになって、寂しくありませんか？","ENG":"Aren't you sad to let the cat go?","TWN":"你們就這樣和貓咪分開不會難過嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"헤헤- 정들었는데 아쉽지 않다고 하면 거짓말이겠지만……","JPN":"えへへっ……せっかく仲良くなれたから、寂しくないといえば嘘ですけど……","ENG":"Heh heh. I'd be lying if I said no...","TWN":"呵呵～相處這麼久一定會有感情的，說不難過是騙人的……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"우리가 찾은 고양이가 사랑해줄 주인이 있는 친구였기 때문에 오히려 더 보람찬 것 같아요!","JPN":"私たちが保護した子に帰りを待つ家族がいたので、頑張った甲斐がありました！","ENG":"But it's also rewarding to know that the cat we've found has such a great owner.","TWN":"不過因為牠有個愛牠的主人，這件事更令我們開心！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"음, 역시 하림 대장이다.","JPN":"うむ、さすがウサギ隊長だ。","ENG":"Mm, Captain Harim is so great.","TWN":"不愧是夏琳老大！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"막시무스 이병…… 아니 루비에겐 정말 잘 된 일이로군.","JPN":"マクシムス二等…いや、ルビーにとって実に喜ばしいことだ。","ENG":"I'm happy for you, Private Maximus—I mean, Ruby.","TWN":"咖啡貓二等兵…不，這對露比來說是最好的結局！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗? 루비야.","JPN":"ん？　ルビー？","ENG":"Ah? Ruby.","TWN":"嗯？露比？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아하하, 간지러워.","JPN":"えへへ、くすぐったいよ。","ENG":"Ah hah hah—it's ticklish!","TWN":"哈哈哈～好癢喔～"},"stage":{"bg":"WHITERABBIT_01","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"와아, 여러분한테 루비가 많이 정이 들었나봐요.","JPN":"わぁ、ルビーは皆さんのことがとても好きみたいですね。","ENG":"Whoa, Ruby must have taken a liking to you.","TWN":"哇～露比也很喜歡你們呢！"},"stage":{"bg":"WHITERABBIT_01","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 부럽다! 하림 언니…","JPN":"いいなあ、 ウサギ隊長……","ENG":"Ah, I'm so jealous, Harim.","TWN":"真羨慕夏琳姐…"},"stage":{"bg":"WHITERABBIT_01","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"나한테도…… 부비부비를 실시해줬으면 하는데, 루비-","JPN":"本官にも……スリスリしてくれないか、ルビー。","ENG":"Why don't you rub against me, too, Ruby?","TWN":"露比…你也來蹭我一下嘛…"},"stage":{"bg":"WHITERABBIT_01","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아하하, 하림이는 좋겠다.","JPN":"あははは、ウサギちゃんが羨ましいわ。","ENG":"Ah hah hah. I'm jealous, too, Harim.","TWN":"哈哈～夏琳一定很開心！"},"stage":{"bg":"WHITERABBIT_01","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……훌륭하군요. 동물 구조대 동아리, 화이트래빗.","JPN":"……素晴らしいですね。動物救助隊サークル、ホワイトラビット。","ENG":"You're amazing. White Rabbits, the animal rescuers.","TWN":"真是不錯……動物救援社團 白兔社。"},"stage":{"bg":"WHITERABBIT_01","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"회장에게도 입부 권한은 있으니, 괜찮지 않을까요?","JPN":"会長にも入部資格はありますよね？","ENG":"Even the Student President has a right to participate in extracurricular activities, right?","TWN":"會長也有權可以加入社團吧？我可以加入嗎？"},"stage":{"bg":"WHITERABBIT_01","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"안 돼. 시엘 화내기 전에 빨리 돌아가야지.","JPN":"あ、いけない、シエルに怒られる前に戻らないと。","ENG":"No. We'd better go back before Ciel really gets mad.","TWN":"不可以！趁西艾爾還沒發火，我們趕快回去吧！"},"stage":{"bg":"WHITERABBIT_01","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CAT_EXTRA_NULL_NULL","text":{"KOREA":"냐앙-","JPN":"ミャー。","ENG":"Meow.","TWN":"喵～"},"stage":{"bg":"WHITERABBIT_01","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_CAT_DAMAGE_DOWN"},{"id":"L6_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"루비야, 이번엔 위험한 데 가지 말고 얌전히 지내야 해?","JPN":"ルビー、これからは危険な場所に一人で行くのはダメよ？","ENG":"Ruby, never run away from home again. Promise?","TWN":"露比～你回家後要乖乖的，不可以再跑到危險的地方喔！"},"stage":{"bg":"WHITERABBIT_01","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"우리도 네 친구들이 다치지 않게 열심히 노력할 테니까!","JPN":"私たちはこれからも、あなたの友達のために頑張るから！","ENG":"We'll continue to do our best to rescue friends like you.","TWN":"我們也會努力守護你的朋友的！"},"stage":{"bg":"WHITERABBIT_01","bgm":"THEMA_WHITERABBIT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};